// Cache para imagens e textos do site
const CACHE_KEY='beni_site_cache';const CACHE_DURATION=5*60*1000;// 5 minutos
export const getCache=page=>{try{const cached=localStorage.getItem(`${CACHE_KEY}_${page}`);if(cached){const{data,timestamp}=JSON.parse(cached);// Retorna cache mesmo se expirado (para mostrar instantâneo)
return{data,isExpired:Date.now()-timestamp>CACHE_DURATION};}}catch(e){console.error('Cache read error:',e);}return{data:null,isExpired:true};};export const setCache=(page,data)=>{try{localStorage.setItem(`${CACHE_KEY}_${page}`,JSON.stringify({data,timestamp:Date.now()}));}catch(e){console.error('Cache write error:',e);}};export const clearCache=()=>{try{Object.keys(localStorage).forEach(key=>{if(key.startsWith(CACHE_KEY)){localStorage.removeItem(key);}});}catch(e){console.error('Cache clear error:',e);}};
